const i = $json || {};
const zalo_user_id = String(i.zalo_user_id || '').trim();
const zalo_msg_id = String(i.zalo_msg_id || '').trim();
const mapped_items = Array.isArray(i.mapped_items) ? i.mapped_items : [];
const unmapped_items = Array.isArray(i.unmapped_items) ? i.unmapped_items : [];
const confidence_meta = i.confidence_meta || {};
const invoice_meta = i.invoice_meta || {};
if (!zalo_user_id || !zalo_msg_id) throw new Error('zalo_user_id and zalo_msg_id are required');
if (!mapped_items.length) throw new Error('mapped_items must contain at least one item for draft preview');

const supplier = String(invoice_meta.supplier_code || invoice_meta.supplier_name || 'UNKNOWN_SUPPLIER');
const total = mapped_items.reduce((s, it) => s + Number((it.converted_qty || it.quantity || 0) * (it.is_promotion ? 0 : (it.converted_unit_price || it.unit_price || 0))), 0);
const topItems = mapped_items.slice(0, 5).map((it) => `- ${it.item_name || it.kiotviet_product_name || it.kiotviet_product_code}: ${(it.converted_qty || it.quantity || 0)} x ${(it.is_promotion ? 0 : (it.converted_unit_price || it.unit_price || 0)).toLocaleString('vi-VN')}đ`).join('\n');
const lowConfidence = Number(confidence_meta.overall_confidence || 0);

const summary = [
  `⚠️ Phiếu nhập cần duyệt (DRAFT)`,
  `Nhà cung cấp: ${supplier}`,
  `Số dòng mapped: ${mapped_items.length}`,
  `Số dòng chưa mapped: ${unmapped_items.length}`,
  `Tổng tạm tính: ${total.toLocaleString('vi-VN')}đ`,
  `Confidence: ${lowConfidence}`,
  `---`,
  topItems || '- (không có dòng hiển thị)'
].join('\n').slice(0, 1900);

const poPayload = {
  branchId: Number($env.KIOTVIET_BRANCH_ID || 1),
  supplierId: Number($env.KIOTVIET_SUPPLIER_ID || 0),
  supplierCode: String($env.KIOTVIET_SUPPLIER_CODE || `NCC_${supplier}`),
  purchaseOrderDetails: mapped_items.map((m) => ({
    productId: m.kiotviet_product_id,
    productCode: m.kiotviet_product_code,
    quantity: Number(m.converted_qty || m.quantity || 0),
    price: m.is_promotion ? 0 : Number(m.converted_unit_price || m.unit_price || 0),
    discount: 0,
    description: m.is_promotion ? 'KM - Hàng tặng (Promo)' : ''
  })),
  status: 1,
  statusValue: 'Phiếu tạm',
  description: `⚠️ DRAFT - Cần duyệt | Bill: ${zalo_msg_id} | Source: Image/Partial`
};

return [{ json: { zalo_user_id, zalo_msg_id, mapped_items, unmapped_items, confidence_meta, invoice_meta, summary, po_payload: poPayload, total_amount: total } }];

const ctx = $('Build Draft Preview').item.json;
const po = $json || {};
const poId = po.id || po.data?.id || null;
const poCode = po.code || po.data?.code || null;
if (!poId) throw new Error('Draft PO creation failed: missing id');

return [{ json: { ...ctx, draft_po_id: poId, draft_po_code: poCode } }];
